  bool operator ==(Object other) =>
      identical(this, other) ||
      other is SyncStatus &&
          runtimeType == other.runtimeType &&
          localHeight == other.localHeight &&
          targetHeight == other.targetHeight &&
          percent == other.percent &&
          eta == other.eta &&
          stage == other.stage &&
          lastCheckpoint == other.lastCheckpoint &&
          blocksPerSecond == other.blocksPerSecond &&
          notesDecrypted == other.notesDecrypted &&
          lastBatchMs == other.lastBatchMs;
}

@freezed
sealed class TunnelMode with _$TunnelMode {
  const TunnelMode._();

  /// Tor (default)
  const factory TunnelMode.tor() = TunnelMode_Tor;

  /// I2P (desktop only)
  const factory TunnelMode.i2P() = TunnelMode_I2p;

  /// SOCKS5 proxy
  const factory TunnelMode.socks5({
    /// Proxy URL
    required String url,
  }) = TunnelMode_Socks5;

  /// Direct connection (no privacy)
  const factory TunnelMode.direct() = TunnelMode_Direct;
}

/// Transaction info
class TxInfo {
  /// Transaction ID
  final String txid;

  /// Block height (None if unconfirmed)
  final int? height;

  /// Timestamp
  final PlatformInt64 timestamp;

  /// Amount (positive for receive, negative for send)
  final PlatformInt64 amount;

  /// Fee
  final BigInt fee;

  /// Memo
  final String? memo;

  /// Confirmed
  final bool confirmed;

  const TxInfo({
    required this.txid,
    this.height,
    required this.timestamp,
    required this.amount,
    required this.fee,
    this.memo,
    required this.confirmed,
  });

  @override
  int get hashCode =>
      txid.hashCode ^
      height.hashCode ^
      timestamp.hashCode ^
      amount.hashCode ^
      fee.hashCode ^
      memo.hashCode ^
      confirmed.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is TxInfo &&
          runtimeType == other.runtimeType &&
          txid == other.txid &&
          height == other.height &&
          timestamp == other.timestamp &&
          amount == other.amount &&
          fee == other.fee &&
          memo == other.memo &&
          confirmed == other.confirmed;
}

/// Background sync result for a specific wallet
class WalletBackgroundSyncResult {
  /// Wallet ID
  final String walletId;

  /// Sync mode that was executed
  final String mode;

  /// Number of blocks synced
  final BigInt blocksSynced;

  /// Starting height
  final BigInt startHeight;

  /// Ending height
  final BigInt endHeight;

  /// Duration in seconds
  final BigInt durationSecs;

  /// Any errors encountered (non-fatal)
  final List<String> errors;

  /// New balance after sync (if changed)
  final BigInt? newBalance;

  /// Number of new transactions
  final int newTransactions;

  const WalletBackgroundSyncResult({
    required this.walletId,
    required this.mode,
    required this.blocksSynced,
    required this.startHeight,
    required this.endHeight,
    required this.durationSecs,
    required this.errors,
    this.newBalance,
    required this.newTransactions,
  });

  @override
  int get hashCode =>
      walletId.hashCode ^
      mode.hashCode ^
      blocksSynced.hashCode ^
      startHeight.hashCode ^
      endHeight.hashCode ^
      durationSecs.hashCode ^
      errors.hashCode ^
      newBalance.hashCode ^
      newTransactions.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is WalletBackgroundSyncResult &&
          runtimeType == other.runtimeType &&
          walletId == other.walletId &&
          mode == other.mode &&
          blocksSynced == other.blocksSynced &&
          startHeight == other.startHeight &&
          endHeight == other.endHeight &&
          durationSecs == other.durationSecs &&
          errors == other.errors &&
          newBalance == other.newBalance &&
          newTransactions == other.newTransactions;
}

/// Wallet metadata
class WalletMeta {
  /// Wallet ID
  final String id;

  /// Wallet name
  final String name;

  /// Created timestamp
  final PlatformInt64 createdAt;

  /// Is watch-only
  final bool watchOnly;

  /// Birthday height
  final int birthdayHeight;

  /// Network type (mainnet, testnet, regtest)
  final String? networkType;

  /// Optional custom lightwalletd endpoint (host:port)
  final String? endpoint;

  const WalletMeta({
    required this.id,
    required this.name,
    required this.createdAt,
    required this.watchOnly,
    required this.birthdayHeight,
    this.networkType,
    this.endpoint,
  });

  @override
  int get hashCode =>
      id.hashCode ^
      name.hashCode ^
      createdAt.hashCode ^
      watchOnly.hashCode ^
      birthdayHeight.hashCode ^
      networkType.hashCode ^
      endpoint.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is WalletMeta &&
          runtimeType == other.runtimeType &&
          id == other.id &&
          name == other.name &&
          createdAt == other.createdAt &&
          watchOnly == other.watchOnly &&
          birthdayHeight == other.birthdayHeight &&
          networkType == other.networkType &&
          endpoint == other.endpoint;
}
